#include <vector>
#include <algorithm>
using namespace std;

const long long INF = 1e18;

long long solve(vector<long long> nums, long long k) {
    int n = nums.size();
    vector<long long> prefix_xor(n + 1, 0);
    for (int i = 1; i <= n; ++i) {
        prefix_xor[i] = prefix_xor[i-1] ^ nums[i-1];
    }
    vector<vector<long long>> dp(n+1, vector<long long>(k+1, INF));
    for (int i = 1; i <= n; ++i) {
        dp[i][1] = prefix_xor[i];
    }
    for (int j = 2; j <= k; ++j) {
        for (int i = j; i <= n; ++i) {
            for (int m = j-1; m <= i-1; ++m) {
                long long current_xor = prefix_xor[i] ^ prefix_xor[m];
                long long current_max = max(dp[m][j-1], current_xor);
                if (dp[i][j] > current_max) {
                    dp[i][j] = current_max;
                }
            }
        }
    }
    return dp[n][k];
}
